const requiredFields = [
      { name: "plant_id", label: "Plant" },
      { name: "packing_no", label: "Packing No" },
      {
        name: "table_hu",
        label: "Handling Unit Table",
        isArray: true,
        arrayType: "object",
        arrayFields: [],
      },
    ];

return {
  required_fields: JSON.stringify(requiredFields),
  entry: JSON.stringify({{workflowparams:entry}})
}

let entry = {{workflowparams:entry}};
const saveAs = {{workflowparams:saveAs}}
let updatedTableHU = [];

for (const [index, huLineItem] of entry.table_hu.entries()) {
  huLineItem.plant_id = entry.plant_id || null;
  huLineItem.customer_id = entry.customer_id || [];
  huLineItem.organization_id = entry.organization_id;
}

if (saveAs === "Draft") {
  if(entry.packing_no_type !== -9999 && (
  !entry.packing_no || entry.packing_no === null || entry.packing_no === ''
)) {
  entry.packing_no = 'draft'
  }
} else {
  if (
  entry.packing_no_type !== -9999 &&
  (!entry.packing_no ||
    entry.packing_no === null ||
    entry.packing_no === "")
) {
  entry.packing_no = 'issued'
  }
}

return {
  table_hu: updatedTableHU,
  packing_no: entry.packing_no,
};

const data = {{workflowparams:entry}};
const packingMode = data.packing_mode;
const tableHU = {{node:code_node_7u6VSG8X.data.table_hu}} || [];

// total_item_qty: sum of each row's rolled-up total_quantity.
// Row total_quantity already includes nested_hu children
// (PackingPickItemToHU sets it from merged temp_data).
data.total_item_qty = tableHU.reduce(
  (total, row) => total + (parseFloat(row.total_quantity) || 0),
  0,
);

// total_hu_count: packing-mode dependent.
if (packingMode === "Basic") {
  data.total_hu_count = tableHU.reduce(
    (total, row) => total + (parseInt(row.hu_quantity) || 0),
    0,
  );
} else {
  data.total_hu_count = tableHU.length;
}

// total_item_count: distinct item_ids across every row's temp_data.
// Flatten nested_hu children so their items contribute too.
const distinctItemIds = new Set();
for (const row of tableHU) {
  let entries;
  try {
    entries = JSON.parse(row.temp_data || "[]");
  } catch (_) {
    entries = [];
  }
  for (const e of entries) {
    if (e && e.type === "nested_hu") {
      for (const c of e.children || []) {
        if (c.item_id) distinctItemIds.add(c.item_id);
      }
    } else if (e && e.item_id) {
      distinctItemIds.add(e.item_id);
    }
  }
}
data.total_item_count = distinctItemIds.size;

data.table_hu = tableHU;

return {
  entry: data,
  entryId: data.id,
};

const data = {{node:code_node_CYy1gmHf.data.entry}};
const tableHU = data.table_hu || [];

// Walk table_hu temp_data (flatten nested_hu children) to collect distinct SO refs.
// For Completed: 1 packing = 1 SO via entry.so_id — wrapped as array for update-node filter.
const uniqueSOLineIds = new Set();
for (const row of tableHU) {
  let entries;
  try { entries = JSON.parse(row.temp_data || "[]"); } catch (_) { entries = []; }
  for (const e of entries) {
    if (e && e.type === "nested_hu") {
      for (const c of e.children || []) {
        if (c.so_line_id) uniqueSOLineIds.add(c.so_line_id);
      }
    } else if (e && e.so_line_id) {
      uniqueSOLineIds.add(e.so_line_id);
    }
  }
}

return {
  uniqueSOIds: [data.so_id].filter(Boolean),
  uniqueSOLineIds: Array.from(uniqueSOLineIds),
};

const entry = {{workflowparams:entry}};
const siblings = {{node:search_node_srMlq8jF.data.data}} || [];

const thisGdId = entry.gd_id;

const stillOpen = siblings.filter((gd) => {
  if (gd.gd_status === "Cancelled") return false;
  if (String(gd.id) === String(thisGdId)) return false;
  return gd.packing_status !== "Completed";
});

const shouldFlipToCompleted = stillOpen.length === 0 ? 1 : 0;

return {
  shouldFlipToCompleted,
  pendingSiblingCount: stillOpen.length,
};

const data = {{node:code_node_CYy1gmHf.data.entry}};
// 1 packing = 1 GD via entry.gd_id — just wrap in array for update-node filter.
// Line-level filter is handled by the downstream buildUpdates node.
return {
  uniqueGDIds: [data.gd_id].filter(Boolean),
};

const allData = {{node:code_node_CYy1gmHf.data.entry}};
const gdLines = {{node:search_node_3K98XCZJ.data.data}} || [];

const locationIds = new Set();
const batchIds = new Set();
const huIds = new Set();

// From packing.table_hu (DB-recorded completed rows)
for (const row of allData.table_hu || []) {
  if (row.location_id) locationIds.add(row.location_id);
  if (row.handling_unit_id) huIds.add(row.handling_unit_id);

  let entries;
  try { entries = JSON.parse(row.temp_data || "[]"); } catch (_) { entries = []; }
  for (const e of entries) {
    if (e && e.type === "nested_hu") {
      if (e.nested_hu_id) huIds.add(e.nested_hu_id);
      for (const c of e.children || []) {
        if (c.location_id) locationIds.add(c.location_id);
        if (c.batch_id) batchIds.add(c.batch_id);
      }
    } else if (e) {
      if (e.location_id) locationIds.add(e.location_id);
      if (e.batch_id) batchIds.add(e.batch_id);
    }
  }
}

// From existing GD line temp_qty_data / temp_hu_data
for (const line of gdLines) {
  let tqd, thd;
  try { tqd = JSON.parse(line.temp_qty_data || "[]"); } catch (_) { tqd = []; }
  try { thd = JSON.parse(line.temp_hu_data || "[]"); } catch (_) { thd = []; }
  for (const entry of tqd) {
    if (entry.location_id) locationIds.add(entry.location_id);
    if (entry.batch_id) batchIds.add(entry.batch_id);
    if (entry.handling_unit_id) huIds.add(entry.handling_unit_id);
  }
  for (const entry of thd) {
    if (entry.location_id) locationIds.add(entry.location_id);
    if (entry.batch_id) batchIds.add(entry.batch_id);
    if (entry.handling_unit_id) huIds.add(entry.handling_unit_id);
  }
}

return {
  locationIds: Array.from(locationIds),
  batchIds: Array.from(batchIds),
  huIds: Array.from(huIds),
};

const allData = {{node:code_node_CYy1gmHf.data.entry}};
const gdLines = {{node:search_node_3K98XCZJ.data.data}} || [];
const locations = {{node:search_node_UsQpPGhM.data.data}} || [];
const batches = {{node:search_node_Nc4I5K4Y.data.data}} || [];
const hus = {{node:search_node_I45K13Jv.data.data}} || [];

const packingId = allData.id || "";

const flattenTempData = (tempData) => {
  const out = [];
  for (const e of tempData || []) {
    if (e && e.type === "nested_hu") {
      for (const c of e.children || []) out.push(c);
    } else if (e) {
      out.push(e);
    }
  }
  return out;
};

const buildGdTempQtyPatches = (completedRows) => {
  const patches = [];
  for (const row of completedRows || []) {
    if (row.hu_row_type === "locked") continue;
    const huId = row.handling_unit_id;
    const huBin = row.location_id;
    if (!huId || !huBin) continue;
    let entries;
    try { entries = JSON.parse(row.temp_data || "[]"); } catch (_) { entries = []; }
    const flat = flattenTempData(entries);
    for (const e of flat) {
      if (!e.gd_line_id) continue;
      patches.push({
        match: {
          gd_line_id: e.gd_line_id,
          material_id: e.item_id,
          batch_id: e.batch_id || null,
          bin_location: e.location_id,
        },
        patch: {
          handling_unit_id: huId,
          bin_location: huBin,
        },
      });
    }
  }
  return patches;
};

const roundQty = (v) => parseFloat(parseFloat(v || 0).toFixed(3));

const buildViewStock = (args) => {
  const { tempQtyData = [], tempHuData = [], gdUom = "", locationMap = {}, batchMap = {}, huNoMap = {} } = args || {};
  const looseEntries = [];
  const huEntries = [];
  for (const e of tempQtyData) {
    const qty = parseFloat(e.gd_quantity != null ? e.gd_quantity : (e.qty != null ? e.qty : e.quantity) || 0) || 0;
    if (qty <= 0) continue;
    const row = { huId: e.handling_unit_id || "", batchId: e.batch_id || null, locationId: e.location_id, qty };
    (row.huId ? huEntries : looseEntries).push(row);
  }
  for (const e of tempHuData) {
    const qty = parseFloat(e.deliver_quantity != null ? e.deliver_quantity : (e.qty != null ? e.qty : e.quantity) || 0) || 0;
    if (qty <= 0) continue;
    huEntries.push({ huId: e.handling_unit_id || "", batchId: e.batch_id || null, locationId: e.location_id, qty });
  }
  const looseTotal = roundQty(looseEntries.reduce((s, e) => s + e.qty, 0));
  const huTotal = roundQty(huEntries.reduce((s, e) => s + e.qty, 0));
  const grandTotal = roundQty(looseTotal + huTotal);
  const formatLooseLine = (e, i) => {
    const name = locationMap[e.locationId] || e.locationId || "(?)";
    let s = (i + 1) + ". " + name + ": " + e.qty + " " + gdUom;
    if (e.batchId) s += "\n[Batch: " + (batchMap[e.batchId] || e.batchId) + "]";
    return s;
  };
  const formatHuLine = (e, i) => {
    const name = huNoMap[e.huId] || e.huId || "(?)";
    let s = (i + 1) + ". " + name + ": " + e.qty + " " + gdUom;
    if (e.batchId) s += "\n   [Batch: " + (batchMap[e.batchId] || e.batchId) + "]";
    return s;
  };
  const hasLoose = looseEntries.length > 0;
  const hasHu = huEntries.length > 0;
  if (!hasLoose && !hasHu) return "";
  if (hasLoose && hasHu) {
    let out = "Total: " + grandTotal + " " + gdUom + "\n\n";
    out += "LOOSE STOCK:\n";
    out += looseEntries.map(formatLooseLine).join("\n");
    out += "\n\nHANDLING UNIT:\n";
    out += huEntries.map(formatHuLine).join("\n");
    return out;
  }
  if (hasHu) {
    let out = "Total: " + huTotal + " " + gdUom + "\n\nHANDLING UNIT:\n";
    out += huEntries.map(formatHuLine).join("\n");
    return out;
  }
  let out = "Total: " + looseTotal + " " + gdUom + "\n\nDETAILS:\n";
  out += looseEntries.map(formatLooseLine).join("\n");
  return out;
};

const locationMap = {};
for (const loc of locations) locationMap[loc.id] = loc.bin_location_combine || loc.name || loc.id;
const batchMap = {};
for (const b of batches) batchMap[b.id] = b.batch_number || b.name || b.id;
const huNoMap = {};
for (const hu of hus) huNoMap[hu.id] = hu.handling_no || hu.id;

const patches = buildGdTempQtyPatches(allData.table_hu || []);
const patchesByLine = {};
for (const p of patches) {
  if (!patchesByLine[p.match.gd_line_id]) patchesByLine[p.match.gd_line_id] = [];
  patchesByLine[p.match.gd_line_id].push(p);
}

const updatedGdLines = [];
for (const line of gdLines) {
  const linePatches = patchesByLine[line.id];
  if (!linePatches || linePatches.length === 0) continue;
  const originalTempQtyData = line.temp_qty_data || "[]";
  let tqd;
  try { tqd = JSON.parse(originalTempQtyData); } catch (_) { tqd = []; }
  const updatedTqd = tqd.map((entry) => {
    const p = linePatches.find((pp) => {
      return (
        String(pp.match.material_id) === String(entry.material_id) &&
        String(pp.match.batch_id || "") === String(entry.batch_id || "") &&
        String(pp.match.bin_location || "") === String(entry.location_id || "") &&
        (!entry.handling_unit_id || entry.handling_unit_id === "")
      );
    });
    if (!p) return entry;
    return Object.assign({}, entry, {
      handling_unit_id: p.patch.handling_unit_id,
      location_id: p.patch.bin_location,
    });
  });
  let tempHuData;
  try { tempHuData = JSON.parse(line.temp_hu_data || "[]"); } catch (_) { tempHuData = []; }
  const gdUom = line.item_uom_name || line.gd_order_uom || line.item_uom || "";
  const viewStock = buildViewStock({
    tempQtyData: updatedTqd,
    tempHuData,
    gdUom,
    locationMap,
    batchMap,
    huNoMap,
  });
  updatedGdLines.push({
    id: line.id,
    temp_qty_data: JSON.stringify(updatedTqd),
    prev_temp_qty_data: originalTempQtyData,
    view_stock: viewStock,
    packing_id: packingId,
  });
}

return { updatedGdLines };

const data = {{node:code_node_CYy1gmHf.data.entry}};
const tableHU = data.table_hu || [];

// Walk table_hu temp_data (flatten nested_hu children) to collect distinct TO line IDs.
// TO is 1:1 with packing via entry.to_id — wrapped as array for update-node filter.
const uniqueTOLineIds = new Set();
for (const row of tableHU) {
  let entries;
  try { entries = JSON.parse(row.temp_data || "[]"); } catch (_) { entries = []; }
  for (const e of entries) {
    if (e && e.type === "nested_hu") {
      for (const c of e.children || []) {
        if (c.to_line_id) uniqueTOLineIds.add(c.to_line_id);
      }
    } else if (e && e.to_line_id) {
      uniqueTOLineIds.add(e.to_line_id);
    }
  }
}

return {
  uniqueTOIds: [data.to_id].filter(Boolean),
  uniqueTOLineIds: Array.from(uniqueTOLineIds),
};

const entry = {{workflowparams:entry}};
const gdData = {{node:get_node_nqe6SJFz.data.data}} || null;

return {
  shouldCallGdWorkflow: (gdData && gdData.id) ? 1 : 0,
  gdData,
};

const data = {{node:code_node_CYy1gmHf.data.entry}}
const tableItems = data.table_items || [];
const packingMode = data.packing_mode;

let uniqueSOIds
let uniqueSOLineIds

if (packingMode === "Basic") {
  //filter duplicated so_id
  uniqueSOIds = [...new Set(tableItems.map((item) => item.so_id))];

  //filter duplicated so_line_id
  uniqueSOLineIds = [...new Set(tableItems.map((item) => item.so_line_id)),
  ];
}

return {
  uniqueSOIds: uniqueSOIds,
  uniqueSOLineIds: uniqueSOLineIds
}

const data = {{node:code_node_CYy1gmHf.data.entry}}
const tableItems = data.table_items || [];
const packingMode = data.packing_mode;

let uniqueGDIds
let uniqueGDLineIds

if (packingMode === "Basic") {
  //filter duplicated gd_id
  uniqueGDIds = [...new Set(tableItems.map((item) => item.gd_id))];

  //filter duplicated gd_line_id
  uniqueGDLineIds = [...new Set(tableItems.map((item) => item.gd_line_id)),
  ];
}

return {
  uniqueGDIds: uniqueGDIds,
  uniqueGDLineIds: uniqueGDLineIds
}

const data = {{node:code_node_CYy1gmHf.data.entry}}
const tableItems = data.table_items || [];
const packingMode = data.packing_mode;

let uniqueTOIds
let uniqueTOLineIds

if (packingMode === "Basic") {
  //filter duplicated to_id
  uniqueTOIds = [...new Set(tableItems.map((item) => item.to_id))];

  //filter duplicated to_line_id
  uniqueTOLineIds = [...new Set(tableItems.map((item) => item.to_line_id)),
  ];
}

return {
  uniqueTOIds: uniqueTOIds,
  uniqueTOLineIds: uniqueTOLineIds
}
